## 💻 Level 1 — Beginner Example
```javascript
function calculateTotal(price) {
  return price + 5;
}
console.log(calculateTotal(10));
```

intermediate_example:
## 💻 Level 2 — Practical Example
```javascript
function getInvoice(subtotal, tax_rate) {
  let tax_amt = subtotal * tax_rate;
  return subtotal + tax_amt;
}
console.log(getInvoice(100, 0.05));
```

advanced_example:
## 💻 Level 3 — Real Project Example
```javascript
function processCheckout(shopping_cart) {
  let total = shopping_cart.reduce((a,b) => a+b, 0);
  if (total > 100) {
    total *= 0.9;
  }
  return total;
}
```

